  "bco|27-5": [{"t":"case","ttl":"2023-22 — Suh v. Korean Southeastern Presbytery","sub":"","yr":2025,"disp":"granted","url":"https://raymond-rishty.github.io/pca-ga/cases/ga52_2025__2023-22.html"},{"t":"case","ttl":"2024-18 — Harris v. Wisconsin Presbytery","sub":"","yr":2025,"disp":"denied","url":"https://raymond-rishty.github.io/pca-ga/cases/ga52_2025__2024-18.html"},{"t":"case","ttl":"2020-09 — RE SEAN OZBALT AND RE ERIN BARR V. PACIFIC PRESBYTERY","sub":"","yr":2022,"disp":"sustained","url":"https://raymond-rishty.github.io/pca-ga/cases/ga49_2022__2020-09.html"},{"t":"case","ttl":"2019-01 — Dodson et al. v. Ohio Presbytery","sub":"","yr":2021,"disp":"other","url":"https://raymond-rishty.github.io/pca-ga/cases/ga48_2021__2019-01.html"},{"t":"case","ttl":"2019-05 — Goggan v. Missouri Presbytery","sub":"","yr":2021,"disp":"denied","url":"https://raymond-rishty.github.io/pca-ga/cases/ga48_2021__2019-05.html"},{"t":"case","ttl":"2009-05/2009-08/2009-09/2009-10 — Martin Payne, James Linton, Kirk Lyons, Robert Woodward v. Western Carolina Presbytery","sub":"","yr":2010,"disp":"denied","url":"https://raymond-rishty.github.io/pca-ga/cases/ga38_2010__2009-05_2009-08_2009-09_2009-10.html"},{"t":"case","ttl":"1993-03 — Judicial Case 93-3","sub":"","yr":1994,"disp":"Reversed; censure removed  ·  **Dissent:** yes","url":"https://raymond-rishty.github.io/pca-ga/cases/ga22_1994__1993-03.html"},{"t":"inq","ttl":"Voluntary resignation from membership and application of BCO 46-5","sub":"The GA clarified that BCO 46-5 had been variously interpreted regarding voluntary resignation, resolving that a simple resignation does not automatically trigger the willful-neglect excommunication process.","yr":1991,"disp":"advice given","url":"https://raymond-rishty.github.io/pca-ga/inquiries/ga19_1991__ci02.html"},{"t":"case","ttl":"2 — Carl Fox v. Mississippi Valley Presbytery et al.","sub":"","yr":1988,"disp":"sustained in part; complaints #1, #3, #4 sustained and re…","url":"https://raymond-rishty.github.io/pca-ga/cases/ga16_1988__case1.html"},{"t":"inq","ttl":"Whether a resignation letter constitutes willful neglect justifying roll erasure","sub":"The CCB held that 'deletion' under BCO 46-5 is equivalent to excommunication and referred the question of easier non-judicial removal to the 17th GA for potential BCO amendment.","yr":1988,"disp":"advice given","url":"https://raymond-rishty.github.io/pca-ga/inquiries/ga16_1988__ci09.html"},{"t":"inq","ttl":"Informal versus formal admonition and due-process requirements under BCO 27-5","sub":"The CCB distinguished informal admonition (ordinary relational correction) from formal judicial admonition, holding that the paragraph in question did not require BCO 27-5 due process.","yr":1987,"disp":"advice given","url":"https://raymond-rishty.github.io/pca-ga/inquiries/ga15_1987__ci01.html"},{"t":"inq","ttl":"Grounds and procedures for removing members from PCA church rolls","sub":"Declining to address case-specific questions, the CCB outlined the three BCO provisions by which members may be removed from church rolls: transfer, discipline, or relocation.","yr":1986,"disp":"declined to answer specific questions; general advice given","url":"https://raymond-rishty.github.io/pca-ga/inquiries/ga14_1986__ci08.html"},{"t":"inq","ttl":"Whether deletion from the roll under BCO 46-5 constitutes excommunication","sub":"The CCB answered yes — 'deletion' under BCO 46-5 is excommunication in effect, and the due-process procedures of BCO 27-5 must therefore be followed.","yr":1986,"disp":"advice given","url":"https://raymond-rishty.github.io/pca-ga/inquiries/ga14_1986__ci09.html"},{"t":"inq","ttl":"Procedure for removing members who relocate without affiliating elsewhere","sub":"BCO 46-2 governs removal of members who move away and fail to affiliate within a year; BCO 46-5's formal discipline applies only to willful neglect, not mere relocation.","yr":1986,"disp":"advice given","url":"https://raymond-rishty.github.io/pca-ga/inquiries/ga14_1986__ci10.html"},{"t":"inq","ttl":"Teaching elder voting rights and congregational approval of pastoral salary changes","sub":"The CCB advised that a teaching elder votes as a full session member, and that any change to pastoral salary terms requires congregational approval as part of the call.","yr":1986,"disp":"advice given","url":"https://raymond-rishty.github.io/pca-ga/inquiries/ga14_1986__ci11.html"},{"t":"inq","ttl":"Whether deletion from the roll under BCO 46-5 constitutes excommunication","sub":"The CCB answered yes — 'deletion' under BCO 46-5 is excommunication in effect, and the due-process procedures of BCO 27-5 must therefore be followed.","yr":1986,"disp":"advice given","url":"https://raymond-rishty.github.io/pca-ga/inquiries/ga14_1986__ci20.html"},{"t":"inq","ttl":"Meaning of willful neglect and gross crime under BCO 46-5 and 30-4","sub":"BCO 46-5 requires due process under BCO 27-5 for incorrigible members, and 'gross crime or heresy' is to be understood in its biblical and moral sense as determined by the church court.","yr":1985,"disp":"advice given","url":"https://raymond-rishty.github.io/pca-ga/inquiries/ga13_1985__ci06.html"},{"t":"case","ttl":"6 — \"Determined Minority\" of New Life Presbyterian Church v. Judicial Commission of Central Carolina Presbytery","sub":"","yr":1983,"disp":"partially sustained  ·  **Dissent:** yes","url":"https://raymond-rishty.github.io/pca-ga/cases/ga11_1983__case4.html"},{"t":"case","ttl":"4 — Vaughn E. Hathaway, Jr., et al. v. Grace Presbytery","sub":"","yr":1982,"disp":"Complaint not sustained; Grace Presbytery acted properly…","url":"https://raymond-rishty.github.io/pca-ga/cases/ga10_1982__case4.html"},{"t":"case","ttl":"6 — Session of First Presbyterian Church, Stanley, North Carolina v. Central Carolina Presbytery","sub":"","yr":1982,"disp":"Mixed: Items 1, 2, and 5 of complaint sustained; Items 3,…","url":"https://raymond-rishty.github.io/pca-ga/cases/ga10_1982__case6.html"}],
